{"styles":{"blocks":{"core/site-tagline":{"typography":{"fontSize":"var(--wp--preset--font-size--medium)"}},"core/site-title":{"typography":{"fontSize":"var(--wp--preset--font-size--medium)","fontStyle":"normal","fontWeight":"500"}},"core/image":{"border":{"radius":"5px"}}},"spacing":{"padding":{"top":"var(--wp--preset--spacing--70)","right":"var(--wp--preset--spacing--50)","bottom":"var(--wp--preset--spacing--70)","left":"var(--wp--preset--spacing--50)"},"blockGap":"0"},"typography":{"fontFamily":"var(--wp--preset--font-family--manrope)","lineHeight":"1.5","letterSpacing":"0.01rem"},"elements":{"h1":{"typography":{"fontStyle":"normal","fontWeight":"600","lineHeight":"1.2"}},"h2":{"typography":{"fontStyle":"normal","fontWeight":"400","fontSize":"var(--wp--preset--font-size--medium)","lineHeight":"1.5"}},"link":{"typography":{"textDecoration":"underline"}}},"css":"a::after {
 content: "↗";
 font-family: "Inter", sans-serif;
 position: relative;
 top: -2px;
 margin-left: 0.5em;
 text-decoration: none;
 pointer-events: none;
}

a.no-arrow::after,
.no-arrow a::after {
 content: none !important;
}"},"settings":{"layout":{"contentSize":"560px","wideSize":"560px"}},"isGlobalStylesUserThemeJSON":true,"version":3}
